<template><div class="login-page"><video class="bg-video" autoplay muted loop playsinline><source src="/cosmora_ai_job_platform_final_20s.mp4" type="video/mp4"></video><div class="bg-mask"></div><div class="page-content"><div class="brand"><div class="brand-title">Qiongjing Cosmora</div><div class="brand-subtitle">AI-Powered Learning Multi-Agent System</div></div><div class="top-right-entry"><button class="entry-btn" @click="openCard('login')">Login</button><span class="entry-divider">.</span><button class="entry-btn" @click="openCard('register')">Register</button><span class="entry-divider">.</span><button class="entry-btn demo-entry" @click="demoLogin">Demo</button></div><div class="glass-card" v-if="showCard"><button class="card-close" @click="showCard=false">x</button><div v-if="mode==='login'" class="card-body"><div class="field"><div class="label">Phone</div><input v-model.trim="loginForm.phone" class="input" type="tel" placeholder="Phone number"></div><div class="field"><div class="label">Password</div><input v-model="loginForm.password" class="input" type="password" placeholder="Password"></div><button class="primary-btn" @click="submitLogin">Login</button></div><div v-else class="card-body"><div class="field"><div class="label">Phone</div><input v-model.trim="registerForm.phone" class="input" type="tel" placeholder="Phone"></div><div class="field"><div class="label">Password</div><input v-model="registerForm.password" class="input" type="password" placeholder="Password"></div><button class="primary-btn" @click="submitRegister">Register</button></div></div></div></div></template><script>import axios from 'axios';export default{name:'LoginGlass',data(){return{showCard:false,mode:'login',loginForm:{phone:'',password:''},registerForm:{phone:'',password:'',schoolName:'',province:'',username:''}}},methods:{openCard(m){this.mode=m;this.showCard=true},async demoLogin(){const r=await axios.post('/api/users/login',{phone:'15023569607',password:'demo123',captchaId:'demo',captchaCode:'demo'});if(r.data&&r.data.success){localStorage.setItem('user',JSON.stringify(r.data.user));this.$router.push('/app/full-chain')}},async submitLogin(){try{const r=await axios.post('/api/users/login',{phone:this.loginForm.phone,password:this.loginForm.password,captchaId:'demo',captchaCode:'demo'});if(r.data&&r.data.success){localStorage.setItem('user',JSON.stringify(r.data.user));this.$router.push('/app/full-chain')}else{this.$message.error(r.data.message||'Login failed')}}catch(e){this.$message.error('Login error')}},async submitRegister(){try{const r=await axios.post('/api/users',this.registerForm);if(r.data&&r.data.success){this.showCard=false;this.mode='login';this.$message.success('Registered! Please login')}else{this.$message.error(r.data.message||'Register failed')}}catch(e){this.$message.error('Register error')}}}}</script>